async function main() {
  const options = parseArgs(process.argv.slice(2));

  if (options.help) {
    printUsage();
    return;
  }

  const cwd = process.cwd();
  const config = await readPublishConfig(options.config, cwd);
  applyConfig(options, config, cwd);
  const source = resolveRequiredPath(options.source || process.env.OBSIDIAN_PUBLISH_DIR, cwd, '--source');
  const vault = options.vault ? path.resolve(cwd, options.vault) : null;
  const outDir = path.resolve(cwd, options.out || DEFAULT_OUT);
  const assetsDir = path.resolve(cwd, options.assets || path.join(DEFAULT_PUBLIC_DIR, DEFAULT_ASSETS_DIR));
  const publicAssetBase = publicBaseForAssets(assetsDir, cwd);
  const warnings = [];
  const notices = [];
  const actions = [];
  const skipped = [];

  await validateSource({ source, vault });
  validateOutputPaths({ source, vault, outDir, assetsDir, cwd });
  const attachmentSearchRoots = resolveAttachmentSearchRoots({
    vault,
    paths: options.attachmentSearchPaths,
  });
  const assetResolver = {
    attachmentSearchRoots,
    stats: {
      ambiguous: 0,
      attachmentSearchPathResolved: 0,
      missing: 0,
      noteRelativeResolved: 0,
      requested: 0,
    },
  };

  const records = await readSourceNotes({
    source,
    warnings,
    skipped,
    requireReadyFrontmatter: options.requireReadyFrontmatter,
  });

  if (records.length === 0) {
    throw new Error(`No Markdown files found in ${source}`);
  }

  assignOutputSlugs(records, warnings);
  const noteIndex = buildNoteIndex(records, warnings);

  const writePlan = [];
  const assetPlan = [];

  for (const record of records) {
    const converted = await convertRecord({
      record,
      source,
      vault,
      outDir,
      assetsDir,
      publicAssetBase,
      noteIndex,
      warnings,
      notices,
      assetPlan,
      assetResolver,
      copyAssets: options.copyAssets,
      resolveWikilinksFromVaultRoot: options.resolveWikilinksFromVaultRoot,
    });
    writePlan.push(converted);
  }

  if (options.clean) {
    await cleanGeneratedOutputs({ outDir, assetsDir, dryRun: options.dryRun, actions, warnings });
  }

  await writeConvertedNotes({ writePlan, dryRun: options.dryRun, actions, warnings });
  await copyAssets({ assetPlan, dryRun: options.dryRun, actions, warnings, copyAssets: options.copyAssets });
  await writeManifest({ writePlan, assetPlan, assetsDir, dryRun: options.dryRun, actions });

  printSummary({
    options,
    source,
    vault,
    outDir,
    assetsDir,
    records,
    assetPlan,
    actions,
    warnings,
    notices,
    skipped,
    attachmentSearchRoots,
    assetStats: assetResolver.stats,
  });

  if (options.strict && warnings.length > 0) {
    process.exitCode = 1;
  }
}

function parseArgs(argv) {
  const options = {
    attachmentSearchPaths: DEFAULT_VAULT_ASSET_SEARCH_ROOTS,
    assets: null,
    clean: false,
    config: null,
    copyAssets: true,
    dryRun: false,
    help: false,
    mode: null,
    out: null,
    requireReadyFrontmatter: false,
    resolveWikilinksFromVaultRoot: true,
    source: null,
    strict: false,
    vault: null,
  };

  for (let index = 0; index < argv.length; index += 1) {
    const arg = argv[index];

    switch (arg) {
      case '--assets':
        options.assets = readArgValue(argv, ++index, arg);
        break;
      case '--clean':
        options.clean = true;
        break;
      case '--config':
        options.config = readArgValue(argv, ++index, arg);
        break;
      case '--dry-run':
        options.dryRun = true;
        break;
      case '--help':
      case '-h':
        options.help = true;
        break;
      case '--out':
        options.out = readArgValue(argv, ++index, arg);
        break;
      case '--mode':
        options.mode = readArgValue(argv, ++index, arg);
        break;
      case '--source':
        options.source = readArgValue(argv, ++index, arg);
        break;
      case '--strict':
        options.strict = true;
        break;
      case '--vault':
        options.vault = readArgValue(argv, ++index, arg);
        break;
      default:
        throw new Error(`Unknown option: ${arg}`);
    }
  }

  return options;
}

async function readPublishConfig(configPath, cwd) {
  if (!configPath) {
    return null;
  }

  const resolved = path.resolve(cwd, configPath);
  let config;
  try {
    config = JSON.parse(await readFile(resolved, 'utf8'));
  } catch (error) {
    throw new Error(`Could not read config ${resolved}: ${error.message}`);
  }
  if (!config || Array.isArray(config) || typeof config !== 'object') {
    throw new Error(`Config must be a JSON object: ${resolved}`);
  }
  return { ...config, __path: resolved };
}

function applyConfig(options, config, cwd) {
  if (!config) {
    return;
  }

  const supported = [
    'vaultRoot',
    'publishSource',
    'mode',
    'copyAssets',
    'resolveWikilinksFromVaultRoot',
    'requireReadyFrontmatter',
    'attachmentSearchPaths',
  ];
  for (const key of Object.keys(config)) {
    if (key !== '__path' && !supported.includes(key) && !key.startsWith('_') && key !== '$schema') {
      throw new Error(`Unsupported config key "${key}" in ${config.__path}`);
    }
  }

  if (config.publishSource !== undefined && typeof config.publishSource !== 'string') {
    throw new Error('Config publishSource must be a string.');
  }
  if (config.vaultRoot !== undefined && typeof config.vaultRoot !== 'string') {
    throw new Error('Config vaultRoot must be a string.');
  }
  for (const key of ['copyAssets', 'resolveWikilinksFromVaultRoot', 'requireReadyFrontmatter']) {
    if (config[key] !== undefined && typeof config[key] !== 'boolean') {
      throw new Error(`Config ${key} must be true or false.`);
    }
  }
  if (config.attachmentSearchPaths !== undefined) {
    options.attachmentSearchPaths = normalizeAttachmentSearchPaths(config.attachmentSearchPaths);
  }

  options.source ??= config.publishSource ? path.resolve(cwd, config.publishSource) : null;
  options.vault ??= config.vaultRoot ? path.resolve(cwd, config.vaultRoot) : null;
  options.copyAssets = config.copyAssets ?? options.copyAssets;
  options.resolveWikilinksFromVaultRoot =
    config.resolveWikilinksFromVaultRoot ?? options.resolveWikilinksFromVaultRoot;
  options.requireReadyFrontmatter = config.requireReadyFrontmatter ?? options.requireReadyFrontmatter;
  applyMode(options, options.mode || config.mode);
  options.configPath = config.__path;
}

function normalizeAttachmentSearchPaths(value) {
  if (!Array.isArray(value) || value.some((item) => typeof item !== 'string' || !item.trim())) {
    throw new Error('Config attachmentSearchPaths must be an array of non-empty relative paths.');
  }
  return value.map((item) => {
    const normalized = item.replace(/\\/g, '/').replace(/^\.\//, '').replace(/\/+$/, '');
    if (!normalized || path.isAbsolute(normalized) || path.win32.isAbsolute(normalized) || normalized.split('/').includes('..')) {
      throw new Error(`Config attachmentSearchPaths entry must stay below vaultRoot: ${item}`);
    }
    return normalized;
  });
}

function applyMode(options, mode) {
  if (!mode) {
    return;
  }
  if (!['dry-run', 'publish', 'strict'].includes(mode)) {
    throw new Error('Config mode must be "dry-run", "publish", or "strict".');
  }
  if (mode === 'dry-run') {
    options.dryRun = true;
  }
  if (mode === 'strict') {
    options.strict = true;
  }
}

function readArgValue(argv, index, option) {
  const value = argv[index];
  if (!value || value.startsWith('--')) {
    throw new Error(`${option} requires a value`);
  }
  return value;
}

function resolveRequiredPath(value, cwd, option) {
  if (!value) {
    throw new Error(`${option} is required. Set OBSIDIAN_PUBLISH_DIR or pass ${option} <path>.`);
  }
  return path.resolve(cwd, value);
}

function printUsage() {
  console.log(`Usage:
  npm run notes:sync -- --source <publish-folder> [options]
  npm run notes:publish:dry

Options:
  --source <path>   Obsidian Publish folder to sync. Required unless OBSIDIAN_PUBLISH_DIR is set.
  --vault <path>    Optional Obsidian vault root for resolving referenced attachments only.
  --config <path>   Local JSON config for publish-folder workflows.
  --mode <mode>     dry-run, publish, or strict.
  --out <path>      Output directory for converted notes. Default: ${DEFAULT_OUT}
  --assets <path>   Output directory for copied attachments. Default: ${DEFAULT_PUBLIC_DIR}/${DEFAULT_ASSETS_DIR}
  --dry-run         Print planned writes and warnings without changing files.
  --clean           Remove previously generated notes/assets before syncing.
  --strict          Exit non-zero when warnings are found.
  --help            Show this help text.`);
}

async function validateSource({ source, vault }) {
  const sourceStat = await stat(source).catch(() => null);
  if (!sourceStat?.isDirectory()) {
    throw new Error(`Source folder does not exist or is not a directory: ${source}`);
  }

  const sourceObsidianDir = path.join(source, '.obsidian');
  if (await pathExists(sourceObsidianDir)) {
    throw new Error(
      `Refusing to sync ${source} because it looks like a full Obsidian vault. Choose the Publish folder instead.`,
    );
  }

  if (vault) {
    const vaultStat = await stat(vault).catch(() => null);
    if (!vaultStat?.isDirectory()) {
      throw new Error(`Vault folder does not exist or is not a directory: ${vault}`);
    }
    if (samePath(source, vault)) {
      throw new Error('Refusing to use the vault root as --source. Use a smaller Obsidian Publish folder.');
    }
  }
}

function resolveAttachmentSearchRoots({ vault, paths }) {
  if (!vault) {
    return [];
  }

  return paths.map((relativePath) => {
    const root = path.resolve(vault, relativePath);
    const rootStat = statSync(root, { throwIfNoEntry: false });
    if (!isPathInside(root, vault) || samePath(root, vault)) {
      throw new Error(`Configured attachmentSearchPaths root is outside vaultRoot: ${relativePath}`);
    }
    return rootStat?.isDirectory() ? { path: root, relativePath } : null;
  }).filter(Boolean);
}

function validateOutputPaths({ source, vault, outDir, assetsDir, cwd }) {
  for (const [label, target] of [
    ['--out', outDir],
    ['--assets', assetsDir],
  ]) {
    if (!isPathInside(target, cwd)) {
      throw new Error(`${label} must stay inside this repository: ${target}`);
    }
    if (isPathInside(target, source)) {
      throw new Error(`${label} must not point inside the Obsidian source folder: ${target}`);
    }
    if (vault && isPathInside(target, vault)) {
      throw new Error(`${label} must not point inside the Obsidian vault folder: ${target}`);
    }
  }
}

function publicBaseForAssets(assetsDir, cwd) {
  for (const publicDirName of [DEFAULT_PUBLIC_DIR, 'public']) {
    const publicDir = path.resolve(cwd, publicDirName);
    if (isPathInside(assetsDir, publicDir)) {
      const relative = slash(path.relative(publicDir, assetsDir));
      return `/${relative}`.replace(/\/+$/, '') || '/';
    }
  }

  return `/${path.basename(assetsDir).replace(/\\/g, '/')}`;
}

async function readSourceNotes({ source, warnings, skipped, requireReadyFrontmatter }) {
  const files = await collectMarkdownFiles(source, skipped);
  const records = [];

  for (const file of files) {
    const raw = await readFile(file, 'utf8');
    const relativePath = slash(path.relative(source, file));
    if (hasUnclosedFrontmatter(raw)) {
      skipped.push({ file: relativePath, reason: 'ambiguous or unclosed frontmatter' });
      continue;
    }
    const { frontmatter, body } = splitFrontmatter(raw);
    const parsedFrontmatter = parseFrontmatter(frontmatter, relativePath, warnings);
    if (parsedFrontmatter.publish !== undefined && typeof parsedFrontmatter.publish !== 'boolean') {
      skipped.push({ file: relativePath, reason: 'ambiguous publish frontmatter value' });
      continue;
    }
    if (parsedFrontmatter.publish === false) {
      skipped.push({ file: relativePath, reason: 'frontmatter publish: false' });
      continue;
    }
    if (requireReadyFrontmatter && parsedFrontmatter.publish !== true) {
      skipped.push({ file: relativePath, reason: 'requireReadyFrontmatter requires publish: true' });
      continue;
    }
    records.push({
      body,
      file,
      frontmatter: parsedFrontmatter,
      relativePath,
      slug: '',
      title: '',
    });
  }

  return records;
}

async function collectMarkdownFiles(root, skipped = []) {
  const results = [];

  async function walk(directory) {
    const entries = await readdir(directory, { withFileTypes: true });
    entries.sort((a, b) => a.name.localeCompare(b.name));

    for (const entry of entries) {
      const skipReason = skipReasonForEntry(entry.name, entry.isDirectory());
      if (skipReason) {
        skipped.push({ file: slash(path.relative(root, path.join(directory, entry.name))), reason: skipReason });
        continue;
      }

      const fullPath = path.join(directory, entry.name);
      if (entry.isDirectory()) {
        await walk(fullPath);
      } else if (entry.isFile() && /\.mdx?$/i.test(entry.name)) {
        results.push(fullPath);
      }
    }
  }

  await walk(root);
  return results;
}

function skipReasonForEntry(name, isDirectory) {
  if (name.startsWith('_')) return 'private-looking name';
  const privateLookingFile = /^(?:private|drafts?|templates?)(?:[\s._-]|$)/i.test(
    path.basename(name, path.extname(name)),
  );
  if (!isDirectory && privateLookingFile) return 'private, draft, or template-looking file';
  if (isDirectory && ['private', 'draft', 'drafts', 'template', 'templates'].includes(name.toLowerCase())) {
    return 'private, draft, or template folder';
  }
  if (['.obsidian', '.git', 'node_modules', '.trash', '.DS_Store'].includes(name) || name.startsWith('~')) {
    return 'system or temporary entry';
  }
  return null;
}

function hasUnclosedFrontmatter(raw) {
  const normalized = raw.replace(/^\uFEFF/, '');
  return normalized.startsWith('---\n') && !/^---\r?\n[\s\S]*?\r?\n---\r?\n?/.test(normalized);
}

function splitFrontmatter(raw) {
  const normalized = raw.replace(/^\uFEFF/, '');
  const match = normalized.match(/^---\r?\n([\s\S]*?)\r?\n---\r?\n?/);
  if (!match) {
    return { frontmatter: '', body: normalized };
  }
  return {
    frontmatter: match[1],
    body: normalized.slice(match[0].length),
  };
}

function parseFrontmatter(raw, relativePath, warnings) {
  const data = {};
  if (!raw.trim()) {
    return data;
  }

  const lines = raw.replace(/\r\n/g, '\n').split('\n');
  let currentKey = null;

  for (const line of lines) {
    if (!line.trim() || line.trim().startsWith('#')) {
      continue;
    }

    const listItem = line.match(/^\s*-\s+(.*)$/);
    if (listItem && currentKey) {
      if (!Array.isArray(data[currentKey])) {
        data[currentKey] = [];
      }
      data[currentKey].push(parseScalar(listItem[1]));
      continue;
    }

    const pair = line.match(/^([A-Za-z0-9_-]+):(?:\s*(.*))?$/);
    if (pair) {
      const [, key, rawValue = ''] = pair;
      const value = rawValue.trim();
      currentKey = key;
      data[key] = value === '' ? [] : parseScalar(value);
      continue;
    }

    warnings.push({
      file: relativePath,
      message: `Could not parse frontmatter line: ${line.trim()}`,
      type: 'frontmatter',
    });
  }

  return data;
}

function parseScalar(value) {
  const trimmed = value.trim();

  if (trimmed === 'true') {
    return true;
  }
  if (trimmed === 'false') {
    return false;
  }
  if (trimmed === 'null' || trimmed === '~') {
    return null;
  }
  if (/^-?\d+(?:\.\d+)?$/.test(trimmed)) {
    return Number(trimmed);
  }
  if (trimmed.startsWith('[') && trimmed.endsWith(']')) {
    return splitInlineArray(trimmed.slice(1, -1)).map(parseScalar);
  }
  if (
    (trimmed.startsWith('"') && trimmed.endsWith('"')) ||
    (trimmed.startsWith("'") && trimmed.endsWith("'"))
  ) {
    return trimmed.slice(1, -1);
  }

  return trimmed;
}

function splitInlineArray(value) {
  const items = [];
  let current = '';
  let quote = null;

  for (let index = 0; index < value.length; index += 1) {
    const char = value[index];
    if ((char === '"' || char === "'") && value[index - 1] !== '\\') {
      quote = quote === char ? null : quote || char;
    }
    if (char === ',' && !quote) {
      items.push(current.trim());
      current = '';
      continue;
    }
    current += char;
  }

  if (current.trim()) {
    items.push(current.trim());
  }

  return items;
}

function assignOutputSlugs(records, warnings) {
  const initial = new Map();

  for (const record of records) {
    record.title = normalizeTitle(record.frontmatter.title || fileTitle(record.relativePath));
    const requestedSlug =
      stringValue(record.frontmatter.slug) ||
      stringValue(record.frontmatter.permalink)?.replace(/^\/?notes\//, '').replace(/\/$/, '') ||
      path.basename(record.relativePath, path.extname(record.relativePath));
    const baseSlug = slugify(requestedSlug) || `note-${shortHash(record.relativePath)}`;
    appendMap(initial, baseSlug, record);
  }

  const used = new Set();

  for (const [baseSlug, group] of initial) {
    for (const record of group) {
      let slug = baseSlug;

      if (group.length > 1) {
        const directoryPrefix = slugify(path.dirname(record.relativePath).replace(/^\.$/, ''));
        slug = slugify([directoryPrefix, baseSlug].filter(Boolean).join('-')) || baseSlug;
      }

      let uniqueSlug = slug;
      let suffix = 2;
      while (used.has(uniqueSlug)) {
        uniqueSlug = `${slug}-${suffix}`;
        suffix += 1;
      }

      if (uniqueSlug !== baseSlug) {
        warnings.push({
          file: record.relativePath,
          message: `Adjusted duplicate note slug "${baseSlug}" to "${uniqueSlug}".`,
          type: 'slug',
        });
      }

      record.slug = uniqueSlug;
      used.add(uniqueSlug);
    }
  }
}

function buildNoteIndex(records, warnings) {
  const index = new Map();

  for (const record of records) {
    const keys = [
      stripMarkdownExtension(record.relativePath),
      path.basename(record.relativePath, path.extname(record.relativePath)),
      record.title,
      record.slug,
    ];

    for (const key of keys) {
      if (key) {
        appendMap(index, linkKey(key), record);
      }
    }
  }

  for (const [key, matches] of index) {
    const uniqueMatches = Array.from(new Set(matches));
    if (uniqueMatches.length > 1 && uniqueMatches.every((match) => path.basename(match.relativePath) === key)) {
      warnings.push({
        file: '(index)',
        message: `Wiki link key "${key}" matches multiple source notes.`,
        type: 'wiki-link',
      });
    }
    index.set(key, uniqueMatches);
  }

  return index;
}

async function convertRecord({
  record,
  source,
  vault,
  outDir,
  assetsDir,
  publicAssetBase,
  noteIndex,
  warnings,
  notices,
  assetPlan,
  assetResolver,
  resolveWikilinksFromVaultRoot,
}) {
  const frontmatter = normalizeFrontmatter({ record, warnings, noteIndex });
  const convertedBody = await convertBody({
    body: record.body,
    record,
    source,
    vault,
    assetsDir,
    publicAssetBase,
    noteIndex,
    warnings,
    notices,
    assetPlan,
    assetResolver,
    resolveWikilinksFromVaultRoot,
  });
  const content = `${formatFrontmatter(frontmatter)}\n${GENERATED_MARKER}\n\n${convertedBody.trim()}\n`;

  return {
    content,
    frontmatter,
    outFile: path.join(outDir, `${record.slug}.md`),
    record,
  };
}

function normalizeFrontmatter({ record, warnings, noteIndex }) {
  const fm = record.frontmatter;
  const bodyWithoutDataview = removeDataviewBlocks(record.body, record.relativePath, []).body;
  const category = normalizeTitle(
    firstString(fm.category, firstArrayItem(fm.categories), titleFromDirectory(record.relativePath), 'Learning Methods'),
  );
  const date = normalizeDate(firstString(fm.date, fm.created, fm.created_at, fm.createdAt), null);
  const updated = normalizeDate(firstString(fm.updated, fm.modified, fm.lastmod, fm.last_modified), null);
  const description = normalizeDescription(firstString(fm.description, fm.summary, fm.excerpt), bodyWithoutDataview);
  const status = normalizeStatus(firstString(fm.status), warnings, record.relativePath);
  const type = normalizeType(firstString(fm.type), category);
  const hierarchy = deriveHierarchyMetadata(record);
  const frontmatter = {
    title: record.title,
    description,
    date: date || todayIsoDate(),
    sourcePath: hierarchy.sourcePath,
    collection: hierarchy.collection,
    modulePath: hierarchy.modulePath,
    module: hierarchy.module,
    isIndex: hierarchy.isIndex,
    noteRole: normalizeNoteRole({ fm, hierarchy, type }),
    category,
    tags: normalizeTags(fm.tags),
    status,
    type,
    featured: booleanValue(fm.featured, false),
    draft: booleanValue(fm.draft, false),
    related: normalizeLinkArray(fm.related, record, noteIndex, warnings),
    prerequisites: normalizeStringArray(fm.prerequisites),
    concepts: normalizeStringArray(firstDefined(fm.concepts, fm.aliases)),
  };

  if (updated) {
    frontmatter.updated = updated;
  }

  const subcategory = firstString(fm.subcategory, fm.area);
  if (subcategory) {
    frontmatter.subcategory = normalizeTitle(subcategory);
  }

  const notePath = firstString(fm.path, fm.learning_path);
  if (notePath) {
    frontmatter.path = normalizeTitle(notePath);
  }

  const order = numberValue(fm.order);
  if (Number.isFinite(order)) {
    frontmatter.order = order;
  }

  const level = stringValue(fm.level)?.toLowerCase();
  if (level && VALID_LEVELS.has(level)) {
    frontmatter.level = level;
  }

  return frontmatter;
}

function deriveHierarchyMetadata(record) {
  const sourcePath = slash(record.relativePath);
  const directory = slash(path.dirname(sourcePath));
  const modulePath = directory && directory !== '.' ? directory.split('/').filter(Boolean) : [];

  return {
    sourcePath,
    collection: modulePath[0],
    modulePath,
    module: modulePath.at(-1),
    isIndex: /^index\.mdx?$/i.test(path.basename(sourcePath)),
  };
}

function normalizeNoteRole({ fm, hierarchy, type }) {
  if (hierarchy.isIndex && hierarchy.modulePath.length === 1) {
    return 'collection-index';
  }
  if (hierarchy.isIndex && hierarchy.modulePath.length >= 2) {
    return 'module-index';
  }

  const noteRole = stringValue(fm.noteRole).toLowerCase();
  if (noteRole && VALID_NOTE_ROLES.has(noteRole)) {
    return noteRole;
  }

  if (VALID_NOTE_ROLES.has(type) && !type.endsWith('-index')) {
    return type;
  }

  return 'learning-note';
}

function removeDataviewBlocks(body, file, warnings) {
  let removed = 0;
  const nextBody = body.replace(
    /(^|\n)(`{3,}|~{3,})\s*(dataviewjs|dataview)\s*\n[\s\S]*?\n\2[ \t]*(?=\n|$)/gi,
    (match, prefix, fence, language) => {
      removed += 1;
      warnings.push({
        file,
        message: `Removed ${language} block.`,
        type: 'dataview',
      });
      return prefix;
    },
  );

  return { body: nextBody, removed };
}

async function convertBody({
  body,
  record,
  source,
  vault,
  assetsDir,
  publicAssetBase,
  noteIndex,
  warnings,
  notices,
  assetPlan,
  assetResolver,
  resolveWikilinksFromVaultRoot,
}) {
  let nextBody = body.replace(/\r\n/g, '\n');
  nextBody = removeDataviewBlocks(nextBody, record.relativePath, warnings).body;
  nextBody = removeObsidianComments(nextBody);
  nextBody = convertCallouts(nextBody);
  nextBody = convertHighlights(nextBody);
  nextBody = normalizeCodeFenceInfoStrings(nextBody);

  nextBody = await replaceAsync(nextBody, /!\[\[([^\]]+)\]\]/g, async (_match, rawTarget) => {
    const target = parseObsidianLink(rawTarget);
    if (isAssetReference(target.path)) {
      return copyAssetReference({
        target,
        alt: target.alias || assetAltText(target.path),
        record,
        source,
        vault,
        assetsDir,
        publicAssetBase,
        warnings,
        notices,
        assetPlan,
        assetResolver,
        embed: true,
      });
    }

    warnings.push({
      file: record.relativePath,
      message: `Converted embedded note "${target.path}" to a regular note link.`,
      type: 'wiki-link',
    });
    return noteMarkdownLink({ target, record, noteIndex, warnings, vault, resolveWikilinksFromVaultRoot });
  });

  nextBody = await replaceAsync(nextBody, /!\[([^\]]*)\]\(([^)\n]+)\)/g, async (match, alt, rawDestination) => {
    const destination = parseMarkdownDestination(rawDestination);
    if (!destination || isExternalUrl(destination.path) || destination.path.startsWith('/')) {
      return match;
    }

    if (isMarkdownNoteReference(destination.path)) {
      const target = parseObsidianLink(destination.path);
      target.alias = alt || target.alias;
      return noteMarkdownLink({ target, record, noteIndex, warnings, vault, resolveWikilinksFromVaultRoot });
    }

    if (!isAssetReference(destination.path)) {
      return match;
    }

    return copyAssetReference({
      target: { path: destination.path, alias: alt },
      alt: alt || assetAltText(destination.path),
      record,
      source,
      vault,
      assetsDir,
      publicAssetBase,
      warnings,
      notices,
      assetPlan,
      assetResolver,
      embed: true,
    });
  });

  nextBody = nextBody.replace(/\[\[([^\]]+)\]\]/g, (_match, rawTarget) => {
    const target = parseObsidianLink(rawTarget);
    if (isAssetReference(target.path)) {
      return assetTextLink({
        target,
        record,
        source,
        vault,
        assetsDir,
        publicAssetBase,
        warnings,
        notices,
        assetPlan,
        assetResolver,
      });
    }
    return noteMarkdownLink({ target, record, noteIndex, warnings, vault, resolveWikilinksFromVaultRoot });
  });

  nextBody = nextBody.replace(/(^|[^!])\[([^\]]+)\]\(([^)\n]+)\)/g, (match, prefix, label, rawDestination) => {
    const destination = parseMarkdownDestination(rawDestination);
    if (!destination || isExternalUrl(destination.path) || destination.path.startsWith('/')) {
      return match;
    }

    if (!isMarkdownNoteReference(destination.path)) {
      return match;
    }

    const target = parseObsidianLink(destination.path);
    target.alias = label;
    return `${prefix}${noteMarkdownLink({ target, record, noteIndex, warnings, vault, resolveWikilinksFromVaultRoot })}`;
  });

  return nextBody;
}

function removeObsidianComments(body) {
  return body.replace(/%%[\s\S]*?%%/g, '');
}

function convertCallouts(body) {
  return body.replace(/^>\s*\[!([A-Za-z0-9_-]+)\][+-]?\s*(.*)$/gm, (_match, kind, title) => {
    const label = title?.trim() ? `${titleCase(kind)}: ${title.trim()}` : titleCase(kind);
    return `> **${label}**`;
  });
}

function convertHighlights(body) {
  return body.replace(/==([^=\n][\s\S]*?[^=\n])==/g, '<mark>$1</mark>');
}

function normalizeCodeFenceInfoStrings(body) {
  const lines = body.split('\n');
  let activeFence = null;

  return lines
    .map((line) => {
      const lineEnding = line.endsWith('\r') ? '\r' : '';
      const content = lineEnding ? line.slice(0, -1) : line;
      const opening = content.match(CODE_FENCE_OPENING_PATTERN);

      if (activeFence) {
        if (isClosingFence(content, activeFence)) {
          activeFence = null;
          return line;
        }

        const normalizedLine = normalizeOpeningFenceLine(opening, lineEnding);
        if (normalizedLine && opening[2].length >= activeFence.length) {
          return normalizedLine;
        }
        return line;
      }

      if (!opening) {
        return line;
      }

      const fence = opening[2];
      activeFence = { char: fence[0], length: fence.length };
      return normalizeOpeningFenceLine(opening, lineEnding) ?? line;
    })
    .join('\n');
}

function normalizeOpeningFenceLine(opening, lineEnding) {
  if (!opening) {
    return null;
  }

  const [, indent, fence, rawInfo] = opening;
  const normalizedInfo = normalizeCodeFenceInfo(rawInfo);
  if (normalizedInfo === rawInfo) {
    return null;
  }

  return `${indent}${fence}${normalizedInfo}${lineEnding}`;
}

function normalizeCodeFenceInfo(rawInfo) {
  const info = rawInfo.match(/^(\s*)(\S+)([\s\S]*)$/);
  if (!info) {
    return rawInfo;
  }

  const [, leadingSpace, language, metadata] = info;
  const normalizedLanguage = CODE_FENCE_LANGUAGE_ALIASES.get(language.toLowerCase());
  if (!normalizedLanguage) {
    return rawInfo;
  }

  return `${leadingSpace}${normalizedLanguage}${metadata}`;
}

function isClosingFence(line, activeFence) {
  const closing = line.match(CODE_FENCE_CLOSING_PATTERN);
  return Boolean(
    closing &&
      closing[1][0] === activeFence.char &&
      closing[1].length >= activeFence.length,
  );
}

function parseObsidianLink(rawTarget) {
  const [rawPath = '', ...aliasParts] = rawTarget.split('|');
  const alias = aliasParts.join('|').trim();
  let targetPath = rawPath.trim();
  let heading = '';
  let block = '';

  const blockIndex = targetPath.indexOf('^');
  if (blockIndex >= 0) {
    block = targetPath.slice(blockIndex + 1).trim();
    targetPath = targetPath.slice(0, blockIndex);
  }

  const headingIndex = targetPath.indexOf('#');
  if (headingIndex >= 0) {
    heading = targetPath.slice(headingIndex + 1).trim();
    targetPath = targetPath.slice(0, headingIndex);
  }

  return {
    alias,
    block,
    heading,
    path: decodeUriPath(targetPath.trim()),
  };
}

function noteMarkdownLink({ target, record, noteIndex, warnings, vault, resolveWikilinksFromVaultRoot }) {
  const label = target.alias || target.heading || path.basename(target.path) || record.title;

  if (!target.path && target.heading) {
    return `[${label}](#${slugifyAnchor(target.heading)})`;
  }

  const resolution = resolveNote(target.path, record, noteIndex);
  if (!resolution) {
    if (resolveWikilinksFromVaultRoot && vault && vaultNoteExists(target.path, record, vault)) {
      warnings.push({
        file: record.relativePath,
        message: `Wiki link "${target.path}" resolves in the vault but is outside the publish folder.`,
        type: 'wiki-link',
      });
    }
    const guessedSlug = slugify(path.basename(target.path, path.extname(target.path))) || 'missing-note';
    warnings.push({
      file: record.relativePath,
      message: `Unresolved wiki link "${target.path}".`,
      type: 'wiki-link',
    });
    return `[${label}](/notes/${guessedSlug}/)`;
  }

  if (resolution.ambiguous) {
    warnings.push({
      file: record.relativePath,
      message: `Ambiguous wiki link "${target.path}" matched multiple notes; using ${resolution.record.relativePath}.`,
      type: 'wiki-link',
    });
  }

  if (target.block) {
    warnings.push({
      file: record.relativePath,
      message: `Dropped unsupported block reference "^${target.block}" in link to "${target.path}".`,
      type: 'wiki-link',
    });
  }

  const anchor = target.heading ? `#${slugifyAnchor(target.heading)}` : '';
  return `[${label}](/notes/${resolution.record.slug}/${anchor})`;
}

function vaultNoteExists(targetPath, record, vault) {
  const target = stripMarkdownExtension(targetPath);
  const candidates = [
    path.resolve(vault, target),
    path.resolve(vault, `${target}.md`),
    path.resolve(vault, `${target}.mdx`),
    path.resolve(vault, path.dirname(record.relativePath), `${target}.md`),
  ];
  return candidates.some((candidate) => isPathInside(candidate, vault) && firstExistingFile([candidate]));
}

function resolveNote(targetPath, record, noteIndex) {
  const target = stripMarkdownExtension(targetPath);
  const candidates = [
    target,
    slash(path.join(path.dirname(record.relativePath), target)),
    path.basename(target),
  ].filter(Boolean);

  for (const candidate of candidates) {
    const matches = noteIndex.get(linkKey(candidate));
    if (matches?.length) {
      return {
        ambiguous: matches.length > 1,
        record: matches[0],
      };
    }
  }

  return null;
}

function assetTextLink({ target, record, source, vault, assetsDir, publicAssetBase, warnings, notices, assetPlan, assetResolver }) {
  const plan = planAssetCopy({
    targetPath: target.path,
    record,
    source,
    vault,
    assetsDir,
    publicAssetBase,
    warnings,
    notices,
    assetPlan,
    assetResolver,
  });
  const label = target.alias || assetAltText(target.path);
  return plan ? `[${label}](${plan.publicPath})` : label;
}

function copyAssetReference({
  target,
  alt,
  record,
  source,
  vault,
  assetsDir,
  publicAssetBase,
  warnings,
  notices,
  assetPlan,
  assetResolver,
  embed,
}) {
  const plan = planAssetCopy({
    targetPath: target.path,
    record,
    source,
    vault,
    assetsDir,
    publicAssetBase,
    warnings,
    notices,
    assetPlan,
    assetResolver,
  });

  if (!plan) {
    return embed ? `![${escapeMarkdownText(alt)}](${target.path})` : escapeMarkdownText(alt);
  }

  if (embed && IMAGE_EXTENSIONS.has(path.extname(plan.source).toLowerCase())) {
    return `![${escapeMarkdownText(alt)}](${plan.publicPath})`;
  }

  return `[${escapeMarkdownText(alt)}](${plan.publicPath})`;
}

function planAssetCopy({ targetPath, record, source, vault, assetsDir, publicAssetBase, warnings, notices, assetPlan, assetResolver }) {
  assetResolver.stats.requested += 1;
  const resolution = resolveAssetPath({
    targetPath,
    record,
    source,
    vault,
    attachmentSearchRoots: assetResolver.attachmentSearchRoots,
  });
  if (resolution.kind === 'ambiguous') {
    assetResolver.stats.ambiguous += 1;
    warnings.push({
      file: record.relativePath,
      message: `AMBIGUOUS_ASSET "${targetPath}": ${resolution.candidates.map(slash).join(', ')}`,
      type: 'asset',
    });
    return null;
  }
  if (resolution.kind === 'missing') {
    assetResolver.stats.missing += 1;
    warnings.push({
      file: record.relativePath,
      message: `Missing referenced asset "${targetPath}".`,
      type: 'asset',
    });
    return null;
  }
  const resolved = resolution.path;
  if (resolution.kind === 'note-relative') {
    assetResolver.stats.noteRelativeResolved += 1;
  }
  if (resolution.kind === 'attachment-search-path') {
    assetResolver.stats.attachmentSearchPathResolved += 1;
    notices.push({
      file: record.relativePath,
      message: `Attachment root resolved "${targetPath}" from ${resolution.root.relativePath}.`,
      type: 'attachment-root',
    });
  }

  const output = resolveAssetOutput({
    resolved,
    record,
    source,
    vault,
    assetsDir,
    publicAssetBase,
    assetPlan,
  });

  if (output.existing) {
    return output.existing;
  }

  if (output.collision) {
    notices.push({
      file: record.relativePath,
      message:
        `Asset output collision for "${output.collision.baseName}" between ` +
        `"${output.collision.existingSource}" and "${output.collision.newSource}"; ` +
        `using "${output.safeName}" for the later asset.`,
      type: 'asset-collision',
    });
  }

  const plan = {
    destination: output.destination,
    publicPath: output.publicPath,
    source: resolved,
  };
  assetPlan.push(plan);
  return plan;
}

function resolveAssetOutput({ resolved, record, source, vault, assetsDir, publicAssetBase, assetPlan }) {
  const outputDirectory = path.join(assetsDir, record.slug);
  const existingForSource = assetPlan.find(
    (plan) => samePath(plan.source, resolved) && samePath(path.dirname(plan.destination), outputDirectory),
  );

  if (existingForSource) {
    return { existing: existingForSource };
  }

  const baseSafeName = safeAssetName(path.basename(resolved));
  const baseDestination = path.join(outputDirectory, baseSafeName);
  const existingAtBase = assetPlan.find((plan) => samePath(plan.destination, baseDestination));

  if (!existingAtBase) {
    return {
      destination: baseDestination,
      publicPath: `${publicAssetBase}/${record.slug}/${baseSafeName}`,
      safeName: baseSafeName,
    };
  }

  const suffix = shortHash(assetSourceKey({ resolved, source, vault }));
  let index = 0;

  while (true) {
    const safeName = appendAssetNameSuffix(
      baseSafeName,
      index === 0 ? suffix : `${suffix}-${index + 1}`,
    );
    const destination = path.join(outputDirectory, safeName);
    const existing = assetPlan.find((plan) => samePath(plan.destination, destination));

    if (!existing) {
      return {
        collision: {
          baseName: baseSafeName,
          existingSource: displayAssetSource(existingAtBase.source),
          newSource: displayAssetSource(resolved),
        },
        destination,
        publicPath: `${publicAssetBase}/${record.slug}/${safeName}`,
        safeName,
      };
    }

    if (samePath(existing.source, resolved)) {
      return { existing };
    }

    index += 1;
  }
}

function appendAssetNameSuffix(safeName, suffix) {
  const extension = path.extname(safeName);
  const stem = path.basename(safeName, extension);
  return `${stem}-${suffix}${extension}`;
}

function assetSourceKey({ resolved, source, vault }) {
  for (const root of [source, vault].filter(Boolean)) {
    if (isPathInside(resolved, root)) {
      return slash(path.relative(root, resolved));
    }
  }
  return slash(path.resolve(resolved));
}

function displayAssetSource(value) {
  return slash(value);
}

function resolveAssetPath({ targetPath, record, source, vault, attachmentSearchRoots }) {
  const cleanTarget = decodeUriPath(targetPath)
    .replace(/^<|>$/g, '')
    .split(/[?#]/)[0]
    .replace(/\\/g, '/');
  const absoluteTarget = path.isAbsolute(cleanTarget) || path.win32.isAbsolute(cleanTarget);

  if (absoluteTarget) {
    const absolute = path.resolve(cleanTarget);
    const allowedRoots = [vault, ...attachmentSearchRoots.map((root) => root.path)].filter(Boolean);
    if (!allowedRoots.some((root) => isPathInside(absolute, root))) {
      return { kind: 'missing' };
    }
    return firstExistingFile([absolute]) ? { kind: 'vault-explicit', path: absolute } : { kind: 'missing' };
  }

  const sourceOrVaultRoots = [source, vault].filter(Boolean);
  const recordDirectory = path.dirname(path.join(source, record.relativePath));
  const noteRelative = firstExistingFileInside(
    [path.resolve(recordDirectory, cleanTarget)],
    sourceOrVaultRoots,
  );
  if (noteRelative) {
    return { kind: 'note-relative', path: noteRelative };
  }

  const publishExplicit = firstExistingFileInside([path.resolve(source, cleanTarget)], sourceOrVaultRoots);
  if (publishExplicit) {
    return { kind: 'publish-explicit', path: publishExplicit };
  }

  if (vault) {
    const vaultExplicit = firstExistingFileInside([path.resolve(vault, cleanTarget)], [vault]);
    if (vaultExplicit) {
      return { kind: 'vault-explicit', path: vaultExplicit };
    }
  }

  for (const root of attachmentSearchRoots) {
    const explicit = firstExistingFileInside([path.resolve(root.path, cleanTarget)], [root.path]);
    if (explicit) {
      return { kind: 'attachment-search-path', path: explicit, root };
    }
  }

  if (path.basename(cleanTarget) === cleanTarget) {
    const matches = attachmentSearchRoots.flatMap((root) =>
      findFilesByBasename(root.path, cleanTarget).map((candidate) => ({ candidate, root })),
    );
    if (matches.length === 1) {
      return { kind: 'attachment-search-path', path: matches[0].candidate, root: matches[0].root };
    }
    if (matches.length > 1) {
      return { kind: 'ambiguous', candidates: matches.map((match) => match.candidate) };
    }
  }

  return { kind: 'missing' };
}

function firstExistingFileInside(candidates, allowedRoots) {
  return firstExistingFile(
    candidates.filter((candidate) => allowedRoots.some((root) => isPathInside(candidate, root))),
  );
}

function findFilesByBasename(root, targetName) {
  const matches = [];
  const target = targetName.toLowerCase();

  function walk(directory) {
    for (const entry of readdirSync(directory, { withFileTypes: true })) {
      const fullPath = path.join(directory, entry.name);
      if (entry.isDirectory()) {
        walk(fullPath);
      } else if (entry.isFile() && entry.name.toLowerCase() === target) {
        matches.push(fullPath);
      }
    }
  }

  walk(root);
  return matches.sort((a, b) => slash(a).localeCompare(slash(b)));
}

function firstExistingFile(candidates) {
  for (const candidate of unique(candidates)) {
    try {
      const fs = statSync(candidate);
      if (fs?.isFile()) {
        return candidate;
      }
    } catch {
      // Keep trying candidates.
    }
  }
  return null;
}

async function writeConvertedNotes({ writePlan, dryRun, actions, warnings }) {
  for (const item of writePlan) {
    const existing = await readFile(item.outFile, 'utf8').catch(() => null);
    const relativeOut = slash(path.relative(process.cwd(), item.outFile));

    if (existing && !existing.includes(GENERATED_MARKER)) {
      warnings.push({
        file: item.record.relativePath,
        message: `Skipped ${relativeOut} because it exists and was not generated by this script.`,
        type: 'write',
      });
      continue;
    }

    actions.push(`${dryRun ? 'would write' : 'wrote'} ${relativeOut}`);

    if (!dryRun) {
      await mkdir(path.dirname(item.outFile), { recursive: true });
      await writeFile(item.outFile, item.content, 'utf8');
    }
  }
}

async function copyAssets({ assetPlan, dryRun, actions, warnings, copyAssets = true }) {
  if (!copyAssets) {
    if (assetPlan.length > 0) {
      warnings.push({
        file: '(assets)',
        message: `Asset copying is disabled; skipped ${assetPlan.length} referenced asset(s).`,
        type: 'asset',
      });
    }
    return;
  }
  for (const plan of assetPlan) {
    const sourceStat = await stat(plan.source).catch(() => null);
    if (!sourceStat?.isFile()) {
      warnings.push({
        file: '(assets)',
        message: `Missing referenced asset "${plan.source}".`,
        type: 'asset',
      });
      continue;
    }

    actions.push(`${dryRun ? 'would copy' : 'copied'} ${slash(path.relative(process.cwd(), plan.destination))}`);

    if (!dryRun) {
      await mkdir(path.dirname(plan.destination), { recursive: true });
      await copyFile(plan.source, plan.destination);
    }
  }
}

async function writeManifest({ writePlan, assetPlan, assetsDir, dryRun, actions }) {
  const manifestPath = path.join(assetsDir, MANIFEST_FILE);
  actions.push(`${dryRun ? 'would write' : 'wrote'} ${slash(path.relative(process.cwd(), manifestPath))}`);

  if (dryRun) {
    return;
  }

  await mkdir(assetsDir, { recursive: true });
  await writeFile(
    manifestPath,
    `${JSON.stringify(
      {
        assets: assetPlan.map((plan) => slash(path.relative(process.cwd(), plan.destination))).sort(),
        generatedAt: new Date().toISOString(),
        noteRecords: writePlan
          .map((item) => ({
            output: slash(path.relative(process.cwd(), item.outFile)),
            slug: item.record.slug,
            sourcePath: item.frontmatter.sourcePath,
            collection: item.frontmatter.collection,
            modulePath: item.frontmatter.modulePath,
            module: item.frontmatter.module,
            isIndex: item.frontmatter.isIndex,
            noteRole: item.frontmatter.noteRole,
          }))
          .sort((a, b) => a.output.localeCompare(b.output)),
        notes: writePlan.map((item) => slash(path.relative(process.cwd(), item.outFile))).sort(),
      },
      null,
      2,
    )}\n`,
    'utf8',
  );
}

async function cleanGeneratedOutputs({ outDir, assetsDir, dryRun, actions, warnings }) {
  const noteFiles = await collectMarkdownFiles(outDir).catch(() => []);

  for (const noteFile of noteFiles) {
    const content = await readFile(noteFile, 'utf8').catch(() => '');
    if (!content.includes(GENERATED_MARKER)) {
      continue;
    }

    actions.push(`${dryRun ? 'would remove' : 'removed'} ${slash(path.relative(process.cwd(), noteFile))}`);

    if (!dryRun) {
      await rm(noteFile, { force: true });
    }
  }

  const manifestPath = path.join(assetsDir, MANIFEST_FILE);
  const manifest = await readJson(manifestPath);

  if (!manifest?.assets?.length) {
    return;
  }

  for (const relativeAsset of manifest.assets) {
    const assetPath = path.resolve(process.cwd(), relativeAsset);
    if (!isPathInside(assetPath, assetsDir)) {
      warnings.push({
        file: '(clean)',
        message: `Skipped manifest asset outside assets directory: ${relativeAsset}`,
        type: 'clean',
      });
      continue;
    }

    actions.push(`${dryRun ? 'would remove' : 'removed'} ${relativeAsset}`);
    if (!dryRun) {
      await rm(assetPath, { force: true });
    }
  }
}

async function readJson(file) {
  try {
    return JSON.parse(await readFile(file, 'utf8'));
  } catch {
    return null;
  }
}

function normalizeDescription(value, body) {
  const description = stringValue(value);
  if (description) {
    return collapseWhitespace(description).slice(0, 240);
  }

  const paragraph = firstParagraph(body);
  if (paragraph) {
    return collapseWhitespace(stripMarkdown(paragraph)).slice(0, 240);
  }

  return 'Working note synced from Obsidian Publish.';
}

function normalizeStatus(value, warnings, file) {
  const status = stringValue(value)?.toLowerCase();
  if (!status) {
    return 'seed';
  }
  if (VALID_STATUS.has(status)) {
    return status;
  }

  warnings.push({
    file,
    message: `Normalized unsupported status "${status}" to "seed".`,
    type: 'frontmatter',
  });
  return 'seed';
}

function normalizeType(value, category) {
  const type = stringValue(value)?.toLowerCase();
  if (type && VALID_TYPES.has(type)) {
    return type;
  }

  const source = `${type || ''} ${category || ''}`.toLowerCase();
  if (source.includes('paper')) {
    return 'paper-reading';
  }
  if (source.includes('project') || source.includes('log')) {
    return 'project-log';
  }
  if (source.includes('workflow')) {
    return 'workflow-note';
  }
  if (source.includes('engineering') || source.includes('mechanical') || source.includes('control')) {
    return 'engineering-note';
  }
  if (source.includes('concept')) {
    return 'concept-note';
  }
  return 'learning-note';
}

function normalizeTags(value) {
  return normalizeStringArray(value).map((tag) => tag.replace(/^#/, '')).filter(Boolean);
}

function normalizeStringArray(value) {
  const values = Array.isArray(value) ? value : value ? [value] : [];
  return unique(
    values
      .flatMap((item) => (typeof item === 'string' && item.includes(',') ? item.split(',') : [item]))
      .map((item) => stringValue(item)?.trim())
      .filter(Boolean),
  );
}

function normalizeLinkArray(value, record, noteIndex, warnings) {
  return normalizeStringArray(value).map((item) => {
    const target = parseObsidianLink(item.replace(/^\[\[|\]\]$/g, ''));
    const resolution = target.path ? resolveNote(target.path, record, noteIndex) : null;
    if (resolution) {
      return resolution.record.slug;
    }
    return slugify(item) || item;
  });
}

function normalizeDate(value, fallback) {
  const raw = stringValue(value);
  if (!raw) {
    return fallback;
  }

  const simpleDate = raw.match(/^\d{4}-\d{2}-\d{2}/);
  if (simpleDate) {
    return simpleDate[0];
  }

  const parsed = new Date(raw);
  if (Number.isNaN(parsed.getTime())) {
    return fallback;
  }
  return parsed.toISOString().slice(0, 10);
}

function formatFrontmatter(frontmatter) {
  const keys = FRONTMATTER_ORDER.filter((key) => frontmatter[key] !== undefined);
  const lines = ['---'];

  for (const key of keys) {
    const value = frontmatter[key];
    if (Array.isArray(value)) {
      if (value.length === 0) {
        lines.push(`${key}: []`);
      } else {
        lines.push(`${key}:`);
        for (const item of value) {
          lines.push(`  - ${formatYamlScalar(item)}`);
        }
      }
      continue;
    }
    lines.push(`${key}: ${formatYamlScalar(value)}`);
  }

  lines.push('---');
  return lines.join('\n');
}

function formatYamlScalar(value) {
  if (typeof value === 'number' || typeof value === 'boolean') {
    return String(value);
  }
  if (value === null || value === undefined) {
    return '""';
  }

  const text = String(value);
  if (/^\d{4}-\d{2}-\d{2}$/.test(text)) {
    return text;
  }
  return JSON.stringify(text);
}

function parseMarkdownDestination(rawDestination) {
  const trimmed = rawDestination.trim();
  const angle = trimmed.match(/^<([^>]+)>/);
  if (angle) {
    return { path: decodeUriPath(angle[1]) };
  }

  const quotedTitle = trimmed.match(/^(.+?)(?:\s+["'][^"']*["'])$/);
  const target = quotedTitle ? quotedTitle[1].trim() : trimmed;
  return target ? { path: decodeUriPath(target) } : null;
}

function isMarkdownNoteReference(value) {
  return /\.mdx?(?:#.*)?$/i.test(value);
}

function isAssetReference(value) {
  const extension = path.extname(value.split('#')[0]).toLowerCase();
  return extension !== '' && ASSET_EXTENSIONS.has(extension) && extension !== '.md';
}

function isExternalUrl(value) {
  return /^(?:https?:|mailto:|tel:|data:)/i.test(value);
}

function safeAssetName(value) {
  const extension = path.extname(value);
  const stem = path.basename(value, extension);
  const safeStem = slugify(stem) || `asset-${shortHash(value)}`;
  return `${safeStem}${extension.toLowerCase()}`;
}

function assetAltText(value) {
  return titleCase(path.basename(value, path.extname(value)).replace(/[-_]+/g, ' '));
}

function titleFromDirectory(relativePath) {
  const directory = slash(path.dirname(relativePath));
  if (!directory || directory === '.') {
    return '';
  }
  return titleCase(directory.split('/')[0].replace(/[-_]+/g, ' '));
}

function fileTitle(relativePath) {
  return titleCase(path.basename(relativePath, path.extname(relativePath)).replace(/[-_]+/g, ' '));
}

function normalizeTitle(value) {
  return titleCase(collapseWhitespace(stringValue(value) || 'Untitled Note'));
}

function titleCase(value) {
  return collapseWhitespace(String(value))
    .split(' ')
    .filter(Boolean)
    .map((word) => {
      if (/^[A-Z0-9&/+-]+$/.test(word)) {
        return word;
      }
      return `${word.charAt(0).toUpperCase()}${word.slice(1)}`;
    })
    .join(' ');
}

function slugify(value) {
  return String(value)
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim()
    .toLowerCase()
    .replace(/&/g, ' ')
    .replace(/[\\/]+/g, ' ')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '');
}

function slugifyAnchor(value) {
  return slugify(value);
}

function shortHash(value) {
  let hash = 0;
  for (let index = 0; index < value.length; index += 1) {
    hash = (hash * 31 + value.charCodeAt(index)) >>> 0;
  }
  return hash.toString(36).slice(0, 6);
}

function linkKey(value) {
  return slash(String(value))
    .replace(/\\/g, '/')
    .replace(/^\/+/, '')
    .replace(/\/+/g, '/')
    .replace(/^\.\//, '')
    .replace(/\.mdx?$/i, '')
    .trim()
    .toLowerCase();
}

function stripMarkdownExtension(value) {
  return slash(String(value)).replace(/\.mdx?$/i, '');
}

function firstParagraph(body) {
  const withoutFrontmatter = body
    .replace(/```[\s\S]*?```/g, '')
    .split('\n')
    .map((line) => line.trim())
    .filter((line) => line && !line.startsWith('#') && !line.startsWith('>') && !line.startsWith('|'));
  return withoutFrontmatter.find((line) => !/^[-*+]\s+/.test(line)) || '';
}

function stripMarkdown(value) {
  return String(value)
    .replace(/!\[[^\]]*]\([^)]*\)/g, '')
    .replace(/\[([^\]]+)]\([^)]*\)/g, '$1')
    .replace(/[`*_>#-]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function collapseWhitespace(value) {
  return String(value).replace(/\s+/g, ' ').trim();
}

function firstString(...values) {
  for (const value of values) {
    const text = stringValue(value);
    if (text) {
      return text;
    }
  }
  return '';
}

function firstDefined(...values) {
  return values.find((value) => value !== undefined && value !== null);
}

function firstArrayItem(value) {
  return Array.isArray(value) ? value[0] : '';
}

function stringValue(value) {
  if (value === undefined || value === null) {
    return '';
  }
  if (Array.isArray(value)) {
    return stringValue(value[0]);
  }
  return String(value).trim();
}

function booleanValue(value, fallback) {
  if (typeof value === 'boolean') {
    return value;
  }
  const text = stringValue(value).toLowerCase();
  if (text === 'true') {
    return true;
  }
  if (text === 'false') {
    return false;
  }
  return fallback;
}

function numberValue(value) {
  if (typeof value === 'number') {
    return value;
  }
  const text = stringValue(value);
  return text ? Number(text) : NaN;
}

function appendMap(map, key, value) {
  if (!map.has(key)) {
    map.set(key, []);
  }
  map.get(key).push(value);
}

function unique(values) {
  return Array.from(new Set(values.filter(Boolean)));
}

function samePath(a, b) {
  return path.resolve(a).toLowerCase() === path.resolve(b).toLowerCase();
}

function isPathInside(child, parent) {
  const relative = path.relative(parent, child);
  return relative === '' || (!relative.startsWith('..') && !path.isAbsolute(relative));
}

function slash(value) {
  return String(value).replace(/\\/g, '/');
}

function decodeUriPath(value) {
  try {
    return decodeURIComponent(value);
  } catch {
    return value;
  }
}

function escapeMarkdownText(value) {
  return String(value).replace(/]/g, '\\]');
}

function todayIsoDate() {
  return new Date().toISOString().slice(0, 10);
}

async function pathExists(value) {
  try {
    await access(value);
    return true;
  } catch {
    return false;
  }
}

async function replaceAsync(value, regex, replacer) {
  const parts = [];
  let lastIndex = 0;
  const matches = Array.from(value.matchAll(regex));

  for (const match of matches) {
    parts.push(value.slice(lastIndex, match.index));
    parts.push(await replacer(...match));
    lastIndex = match.index + match[0].length;
  }

  parts.push(value.slice(lastIndex));
  return parts.join('');
}

function printSummary({
  options,
  source,
  vault,
  outDir,
  assetsDir,
  records,
  assetPlan,
  actions,
  warnings,
  notices,
  skipped,
  attachmentSearchRoots,
  assetStats,
}) {
  const mode = options.dryRun ? 'dry run' : 'sync';
  const unresolvedLinks = warnings.filter((warning) => warning.message.startsWith('Unresolved wiki link')).length;
  const missingAssets = warnings.filter((warning) => warning.message.startsWith('Missing referenced asset')).length;
  const ambiguousAssets = warnings.filter((warning) => warning.message.startsWith('AMBIGUOUS_ASSET')).length;
  const slugConflicts = warnings.filter((warning) => warning.type === 'slug').length;
  const skippedWrites = warnings.filter((warning) => warning.type === 'write').length;
  console.log(`\nObsidian notes ${mode} complete`);
  console.log(`Config file used: ${options.configPath || 'none (command line or OBSIDIAN_PUBLISH_DIR)'}`);
  console.log(`Publish folder used: ${source}`);
  console.log(`Vault root used: ${vault || 'not configured'}`);
  console.log(`Attachment roots: ${attachmentSearchRoots.length ? attachmentSearchRoots.map((root) => root.relativePath).join(', ') : 'none'}`);
  console.log(`Notes:  ${outDir}`);
  console.log(`Assets: ${assetsDir}`);
  console.log(`Notes found: ${records.length + skipped.length}`);
  console.log(`Notes skipped: ${skipped.length + skippedWrites}`);
  console.log(`Notes converted: ${records.length}`);
  console.log(`Assets ${options.copyAssets ? (options.dryRun ? 'planned' : 'copied') : 'skipped'}: ${assetPlan.length}`);
  console.log(`Unresolved links: ${unresolvedLinks}`);
  console.log(`Missing assets: ${missingAssets}`);
  console.log(`Ambiguous assets: ${ambiguousAssets}`);
  console.log(`Assets requested: ${assetStats.requested}`);
  console.log(`Note-relative assets resolved: ${assetStats.noteRelativeResolved}`);
  console.log(`Attachment-search-path assets resolved: ${assetStats.attachmentSearchPathResolved}`);
  console.log(`Slug conflicts: ${slugConflicts}`);
  console.log(`Blocking errors: ${options.strict ? warnings.length : 0}`);

  if (skipped.length > 0) {
    console.log('\nSkipped source entries:');
    for (const item of skipped) {
      console.log(`- ${item.file}: ${item.reason}`);
    }
  }

  if (actions.length > 0) {
    console.log('\nActions:');
    for (const action of actions) {
      console.log(`- ${action}`);
    }
  }

  if (notices.length > 0) {
    console.log('\nNotices (non-blocking):');
    for (const notice of notices) {
      console.log(`- [${notice.type}] ${notice.file}: ${notice.message}`);
    }
  }

  if (warnings.length > 0) {
    console.log('\nWarnings:');
    for (const warning of warnings) {
      console.log(`- [${warning.type}] ${warning.file}: ${warning.message}`);
    }
  } else {
    console.log('\nWarnings: none');
  }
}
